            "logoUrl": "https://media.licdn.com/dms/image/v2/D560BAQEmMcvD35jQ8g/company-logo_400_400/B56ZsoFr.jHsAc-/0/1765904138659/nomadglobalapp_logo?e=1778716800&v=beta&t=J77RpY75KpDPCvaCGSZscoBNzgX8yHd0xMeiFnEwHR4",
